const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const sqs = new SQSClient({ region: "us-west-2" });
const queueUrl = "https://sqs.us-west-2.amazonaws.com/123456789012/payment-queue";

async function receiveAndProcessMessages() {
  const params = {
    QueueUrl: queueUrl,
    MaxNumberOfMessages: 10,
    WaitTimeSeconds: 20,
  };

  try {
    const data = await sqs.send(new ReceiveMessageCommand(params));
    if (!data.Messages) {
      console.log("No messages received.");
      return;
    }

    for (const message of data.Messages) {
      const transaction = JSON.parse(message.Body);
      // Process the transaction
      updateDatabase(transaction);

      // Delete the message from SQS
      await sqs.send(new DeleteMessageCommand({
        QueueUrl: queueUrl,
        ReceiptHandle: message.ReceiptHandle,
      }));
    }
  } catch (error) {
    console.error("Error receiving or processing messages:", error);
  }
}

